import { prismaScalarToTs } from './prisma-type-to-ts'

describe('prismaScalarToTs', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['Decimal', 'number'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Uint8Array'],
  ] as const)('maps %s to %s', (prismaType, expected) => {
    expect(prismaScalarToTs(prismaType)).toBe(expected)
  })

  test('returns unknown for unrecognized types', () => {
    expect(prismaScalarToTs('CustomType')).toBe('unknown')
  })
})

