import type * as DMMF from '@prisma/dmmf'

function generateEnumDeclaration(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  const doc = e.documentation ? `/** ${e.documentation} */\n` : ''
  return `${doc}export type ${e.name} = ${values}`
}

/**
 * Generates the `_enums.ts` file containing TypeScript string-union types for all Prisma enums.
 * Returns `null` when the schema has no enums.
 */
export function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string | null {
  if (enums.length === 0) return null
  return enums.map(generateEnumDeclaration).join('\n\n') + '\n'
}

