/**
 * Generates the `index.ts` barrel for the output directory.
 * Re-exports all model types, input types, REST client classes, and optionally enums.
 */
export function generateIndexFile(models: readonly DMMF.Model[], hasEnums: boolean): string {
  const lines: string[] = []

  if (hasEnums) {
    lines.push(`export type * from './_enums'`)
  }

  for (const model of models) {
    lines.push(
      `export type { ${model.name}, ${model.name}WhereUniqueInput, ${model.name}CreateInput, ${model.name}UpdateInput } from './${model.name}'`,
    )
    lines.push(`export { ${model.name}RestClient } from './${model.name}'`)
  }

  lines.push('')
  return lines.join('\n')
}

