import type * as DMMF from '@prisma/dmmf'

import { prismaScalarToTs } from '../prisma-type-to-ts'

/**
 * Derives the REST path segment for a model (e.g. "User" → "users", "Post" → "posts").
 * Appends an "s" suffix after lowercasing the first character for a consistent,
 * predictable convention that users can override at the HTTP routing layer.
 */
function toRestPath(modelName: string): string {
  return modelName.charAt(0).toLowerCase() + modelName.slice(1) + 's'
}

/** Returns the TypeScript base type for a field (scalar, enum, or relation type name). */
function fieldBaseType(field: DMMF.Field): string {
  if (field.kind === 'scalar') return prismaScalarToTs(field.type)
  return field.type
}

/** Returns the full TypeScript type for a field, accounting for lists. */
function fieldTsType(field: DMMF.Field): string {
  const base = fieldBaseType(field)
  return field.isList ? `${base}[]` : base
}

/** Finds the first @id field in a model, used to build URL path segments. */
function findIdField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId)
}

/** Returns the names of enum types referenced by a model's fields. */
function referencedEnums(model: DMMF.Model): string[] {
  return [...new Set(model.fields.filter((f) => f.kind === 'enum').map((f) => f.type))]
}

function generateModelInterface(model: DMMF.Model): string {
  const doc = model.documentation ? `/** ${model.documentation} */` : `/** Represents a ${model.name} record from the database. */`
  const properties = model.fields.map((f) => {
    if (f.kind === 'object') {
      // Relations are optional since they are not always loaded with the record.
      return `  ${f.name}?: ${fieldTsType(f)}`
    }
    const type = f.isRequired ? fieldTsType(f) : `${fieldTsType(f)} | null`
    return `  ${f.name}: ${type}`
  })
  return `${doc}\nexport interface ${model.name} {\n${properties.join('\n')}\n}`
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => (f.isId || f.isUnique) && f.kind !== 'object')
  const properties = uniqueFields.map((f) => `  ${f.name}?: ${fieldTsType(f)}`)
  return `/** Input for identifying a unique ${model.name} record. */\nexport interface ${model.name}WhereUniqueInput {\n${properties.join('\n')}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(
    (f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt,
  )
  const properties = fields.map((f) => {
    const type = fieldTsType(f)
    // Fields with a default or that are nullable become optional in create input.
    const isOptional = !f.isRequired || f.hasDefaultValue
    const nullSuffix = !f.isRequired ? ' | null' : ''
    return isOptional ? `  ${f.name}?: ${type}${nullSuffix}` : `  ${f.name}: ${type}`
  })
  return `/** Input for creating a new ${model.name} record. */\nexport interface ${model.name}CreateInput {\n${properties.join('\n')}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(
    (f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated && !f.isId && !f.isUpdatedAt,
  )
  const properties = fields.map((f) => {
    const type = fieldTsType(f)
    const nullSuffix = !f.isRequired ? ' | null' : ''
    return `  ${f.name}?: ${type}${nullSuffix}`
  })
  return `/** Input for updating an existing ${model.name} record. */\nexport interface ${model.name}UpdateInput {\n${properties.join('\n')}\n}`
}

function generateRestClient(model: DMMF.Model): string {
  const restPath = toRestPath(model.name)
  const idField = findIdField(model)
  // Fall back to the first key in the where object when there is no single @id field.
  const idExpr = idField
    ? `where.${idField.name}`
    : `where[Object.keys(where)[0] as keyof ${model.name}WhereUniqueInput]`

  return [
    `/** REST client for the \`/${restPath}\` resource. */`,
    `export class ${model.name}RestClient {`,
    `  #baseUrl: string`,
    ``,
    `  constructor(baseUrl: string) {`,
    `    this.#baseUrl = baseUrl.replace(/\\/+$/, '')`,
    `  }`,
    ``,
    `  /** Fetches a list of ${model.name} records. */`,
    `  async findMany(options?: RequestOptions): Promise<${model.name}[]> {`,
    `    return httpGet<${model.name}[]>(\`\${this.#baseUrl}/${restPath}\`, options)`,
    `  }`,
    ``,
    `  /** Fetches a single ${model.name} record by its unique identifier. */`,
    `  async findUnique(where: ${model.name}WhereUniqueInput, options?: RequestOptions): Promise<${model.name} | null> {`,
    `    return httpGet<${model.name} | null>(\`\${this.#baseUrl}/${restPath}/\${${idExpr}}\`, options)`,
    `  }`,
    ``,
    `  /** Creates a new ${model.name} record. */`,
    `  async create(data: ${model.name}CreateInput, options?: RequestOptions): Promise<${model.name}> {`,
    `    return httpPost<${model.name}>(\`\${this.#baseUrl}/${restPath}\`, data, options)`,
    `  }`,
    ``,
    `  /** Updates an existing ${model.name} record. */`,
    `  async update(`,
    `    where: ${model.name}WhereUniqueInput,`,
    `    data: ${model.name}UpdateInput,`,
    `    options?: RequestOptions,`,
    `  ): Promise<${model.name}> {`,
    `    return httpPatch<${model.name}>(\`\${this.#baseUrl}/${restPath}/\${${idExpr}}\`, data, options)`,
    `  }`,
    ``,
    `  /** Deletes a ${model.name} record. */`,
    `  async delete(where: ${model.name}WhereUniqueInput, options?: RequestOptions): Promise<${model.name}> {`,
    `    return httpDelete<${model.name}>(\`\${this.#baseUrl}/${restPath}/\${${idExpr}}\`, options)`,
    `  }`,
    `}`,
  ].join('\n')
}

/** Generates the TypeScript source file for a single Prisma model. */
export function generateModelFile(model: DMMF.Model, enumNames: readonly string[]): string {
  const usedEnums = referencedEnums(model).filter((e) => enumNames.includes(e))

  const lines: string[] = [
    `import type { RequestOptions } from './_http-client'`,
    `import { httpDelete, httpGet, httpPatch, httpPost } from './_http-client'`,
  ]

  if (usedEnums.length > 0) {
    lines.push(`import type { ${usedEnums.join(', ')} } from './_enums'`)
  }

  lines.push('')
  lines.push(generateModelInterface(model))
  lines.push('')
  lines.push(generateWhereUniqueInput(model))
  lines.push('')
  lines.push(generateCreateInput(model))
  lines.push('')
  lines.push(generateUpdateInput(model))
  lines.push('')
  lines.push(generateRestClient(model))
  lines.push('')

  return lines.join('\n')
}

