import { describe, expect, test } from 'vitest'

import type * as DMMF from '@prisma/dmmf'

import { generateModelFile } from './model-file'

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'createdAt',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'DateTime',
      hasDefaultValue: true,
      default: { name: 'now', args: [] },
    },
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

describe('generateModelFile', () => {
  test('emits the model interface with correct scalar types', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('export interface User {')
    expect(output).toContain('id: number')
    expect(output).toContain('email: string')
    expect(output).toContain('name: string | null')
    expect(output).toContain('createdAt: Date')
  })

  test('emits WhereUniqueInput only for @id and @unique fields', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('id?: number')
    expect(output).toContain('email?: string')
    // Non-unique fields must not appear in WhereUniqueInput.
    expect(output).not.toMatch(/UserWhereUniqueInput \{[^}]*\bname\b/s)
  })

  test('emits CreateInput marking fields-with-defaults as optional', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('export interface UserCreateInput {')
    // email is required with no default — must be required.
    expect(output).toContain('email: string')
    // name is nullable — must be optional.
    expect(output).toContain('name?: string | null')
    // id and createdAt have defaults — must be optional.
    expect(output).toContain('id?:')
    expect(output).toContain('createdAt?:')
  })

  test('emits UpdateInput with all non-id scalar fields as optional', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('email?: string')
    expect(output).toContain('name?: string | null')
    // id must not appear in UpdateInput.
    expect(output).not.toMatch(/UserUpdateInput \{[^}]*\bid\b/s)
  })

  test('emits a RestClient class with all five CRUD methods', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('export class UserRestClient {')
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  test('uses lowercase-plural model name as REST path', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('/users')
  })

  test('uses the @id field name in URL path expressions', () => {
    const output = generateModelFile(userModel, [])
    expect(output).toContain('where.id')
  })

  test('renders relation fields as optional in the interface', () => {
    const modelWithRelation: DMMF.Model = {
      ...userModel,
      fields: [
        ...userModel.fields,
        {
          kind: 'object',
          name: 'posts',
          isRequired: true,
          isList: true,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'Post',
          hasDefaultValue: false,
          relationName: 'UserToPost',
          relationFromFields: [],
          relationToFields: [],
        },
      ],
    }
    const output = generateModelFile(modelWithRelation, [])
    expect(output).toContain('posts?: Post[]')
  })

  test('imports enum types from _enums when the model references them', () => {
    const modelWithEnum: DMMF.Model = {
      ...userModel,
      name: 'Profile',
      fields: [
        ...userModel.fields,
        {
          kind: 'enum',
          name: 'role',
          isRequired: true,
          isList: false,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          type: 'Role',
          hasDefaultValue: false,
        },
      ],
    }
    const output = generateModelFile(modelWithEnum, ['Role'])
    expect(output).toContain(`import type { Role } from './_enums'`)
    expect(output).toContain('role: Role')
  })

  test('does not emit an enum import when no enums are used', () => {
    const output = generateModelFile(userModel, ['Role'])
    expect(output).not.toContain(`from './_enums'`)
  })
})

