import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator-helper'

import { generateEnumsFile } from './codegen/enums-file'
import { generateHttpClientFile } from './codegen/http-client-file'
import { generateIndexFile } from './codegen/index-file'
import { generateModelFile } from './codegen/model-file'

export function onManifest(_config: GeneratorConfig): GeneratorManifest {
  return {
    prettyName: 'REST API Client',
    defaultOutput: 'generated/rest-client',
    requiresEngines: [],
  }
}

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputValue = options.generator.output?.value
  if (!outputValue) {
    throw new Error(
      'Output directory is required. Set `output` in the generator block of your Prisma schema.',
    )
  }

  const outputDir = path.resolve(outputValue)
  fs.mkdirSync(outputDir, { recursive: true })

  const { models, enums } = options.dmmf.datamodel
  const enumNames = enums.map((e) => e.name)

  const enumsCode = generateEnumsFile(enums)
  if (enumsCode !== null) {
    fs.writeFileSync(path.join(outputDir, '_enums.ts'), enumsCode)
  }

  fs.writeFileSync(path.join(outputDir, '_http-client.ts'), generateHttpClientFile())

  for (const model of models) {
    fs.writeFileSync(path.join(outputDir, `${model.name}.ts`), generateModelFile(model, enumNames))
  }

  fs.writeFileSync(path.join(outputDir, 'index.ts'), generateIndexFile(models, enumsCode !== null))
}

